def _size_for(prefix: str) -> int:
    p = Path(prefix)
    base_dir = p.parent
    stem = p.stem
    total = 0
    for f in base_dir.iterdir():
        if f.is_file() and f.name.startswith(stem):
            total += f.stat().st_size
    return total

